import React, { useEffect, useMemo, useState } from 'react';
import './styles.css';
import {
  Layout,
  Menu,
  Breadcrumb,
  Typography,
  Select,
  Input,
  Table,
  Badge,
  Button,
  Avatar,
  Space,
  Flex,
  Alert,
} from 'antd';
import type { MenuProps, TableProps } from 'antd';
import {
  DashboardOutlined,
  DesktopOutlined,
  MessageOutlined,
  FileTextOutlined,
  SettingOutlined,
  LogoutOutlined,
  BellOutlined,
  PlusOutlined,
  SearchOutlined,
  RightOutlined,
  LeftOutlined,
} from '@ant-design/icons';
import {
  ActivityStatus,
  ConnectionStatus,
  DeviceItem,
  addDevice,
  createDevice,
  fetchDevices,
  selectDevices,
  selectDevicesError,
  selectDevicesLoading,
} from '../../store/deviceSlice';
import { useAppDispatch, useAppSelector } from '../../store/hooks';

const { Header, Content, Sider } = Layout;
const { Title, Text } = Typography;
const { Option } = Select;

type MenuItem = Required<MenuProps>['items'][number];
type ActivityFilter = 'all' | 'active' | 'inactive';
type ConnectionFilter = 'all' | 'connected' | 'disconnected';

type DeviceForm = {
  code: string;
  name: string;
  ip: string;
  activityStatus: ActivityStatus;
  connectionStatus: ConnectionStatus;
  services: string;
};

const activityLabels: Record<ActivityStatus, string> = {
  active: 'Ho?t d?ng',
  inactive: 'Ngung ho?t d?ng',
};

const connectionLabels: Record<ConnectionStatus, string> = {
  connected: 'K?t n?i',
  disconnected: 'M?t k?t n?i',
};

function getItem(
  label: React.ReactNode,
  key: React.Key,
  icon?: React.ReactNode,
  children?: MenuItem[],
): MenuItem {
  return {
    key,
    icon,
    children,
    label,
  } as MenuItem;
}

const menuItems: MenuItem[] = [
  getItem('Dashboard', '1', <DashboardOutlined />),
  getItem('Thi?t b?', '2', <DesktopOutlined />),
  getItem('D?ch v?', '3', <MessageOutlined />),
  getItem('C?p s?', '4', <FileTextOutlined />),
  getItem('B�o c�o', '5', <FileTextOutlined />),
  getItem('C�i d?t h? th?ng', '6', <SettingOutlined />),
];

const initialForm: DeviceForm = {
  code: '',
  name: '',
  ip: '',
  activityStatus: 'active',
  connectionStatus: 'connected',
  services: '',
};

const Device: React.FC = () => {
  const dispatch = useAppDispatch();
  const devices = useAppSelector(selectDevices);
  const loading = useAppSelector(selectDevicesLoading);
  const error = useAppSelector(selectDevicesError);

  const [activityFilter, setActivityFilter] = useState<ActivityFilter>('all');
  const [connectionFilter, setConnectionFilter] = useState<ConnectionFilter>('all');
  const [keyword, setKeyword] = useState<string>('');
  const [page, setPage] = useState<number>(1);
  const [isAdding, setIsAdding] = useState<boolean>(false);
  const [form, setForm] = useState<DeviceForm>(initialForm);
  const [formError, setFormError] = useState<string | undefined>(undefined);
  const [submitting, setSubmitting] = useState<boolean>(false);

  const pageSize = 2;

  useEffect(() => {
    dispatch(fetchDevices());
  }, [dispatch]);

  useEffect(() => {
    setPage(1);
  }, [activityFilter, connectionFilter, keyword]);

  const filteredData = useMemo(() => {
    const normalizedKeyword = keyword.trim().toLowerCase();

    return devices.filter((device) => {
      const matchesActivity =
        activityFilter === 'all' ? true : device.activityStatus === activityFilter;
      const matchesConnection =
        connectionFilter === 'all' ? true : device.connectionStatus === connectionFilter;
      const matchesKeyword =
        normalizedKeyword.length === 0
          ? true
          : `${device.code} ${device.name} ${device.ip} ${device.services.join(' ')}`
              .toLowerCase()
              .includes(normalizedKeyword);

      return matchesActivity && matchesConnection && matchesKeyword;
    });
  }, [devices, activityFilter, connectionFilter, keyword]);

  const paginatedData = useMemo(
    () => filteredData.slice((page - 1) * pageSize, page * pageSize),
    [filteredData, page, pageSize],
  );

  const columns: TableProps<DeviceItem>['columns'] = [
    { title: 'M� thi?t b?', dataIndex: 'code', key: 'code' },
    { title: 'T�n thi?t b?', dataIndex: 'name', key: 'name' },
    { title: '�?a ch? IP', dataIndex: 'ip', key: 'ip' },
    {
      title: 'Tr?ng th�i ho?t d?ng',
      dataIndex: 'activityStatus',
      key: 'activityStatus',
      render: (value: DeviceItem['activityStatus'], record) => (
        <Badge
          status={value === 'active' ? 'success' : 'error'}
          text={record.activityLabel || activityLabels[value] || value}
        />
      ),
    },
    {
      title: 'Tr?ng th�i k?t n?i',
      dataIndex: 'connectionStatus',
      key: 'connectionStatus',
      render: (value: DeviceItem['connectionStatus'], record) => (
        <Badge
          status={value === 'connected' ? 'success' : 'error'}
          text={record.connectionLabel || connectionLabels[value] || value}
        />
      ),
    },
    {
      title: 'D?ch v? s? d?ng',
      dataIndex: 'services',
      key: 'services',
      render: (services: string[]) => (
        <div>
          {services.join(', ')}
          <br />
          <a href="services.tsx">Xem th�m</a>
        </div>
      ),
      width: 250,
    },
    {
      title: '',
      key: 'actionDetail',
      render: () => <a href="service_detail.tsx">Chi ti?t</a>,
    },
    {
      title: '',
      key: 'actionUpdate',
      render: () => <a href="service_update.tsx">C?p nh?t</a>,
    },
  ];

  const handleFormChange = (field: keyof DeviceForm, value: string) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  const handleAddDevice = () => {
    setForm(initialForm);
    setFormError(undefined);
    setIsAdding(true);
  };

  const handleSubmit = async () => {
    if (!form.code.trim() || !form.name.trim() || !form.ip.trim()) {
      setFormError('Vui l�ng nh?p M� thi?t b?, T�n thi?t b? v� �?a ch? IP.');
      return;
    }
    setSubmitting(true);

    const servicesArray = form.services
      .split(',')
      .map((s) => s.trim())
      .filter(Boolean);

    const newDevicePayload = {
      code: form.code.trim(),
      name: form.name.trim(),
      ip: form.ip.trim(),
      activityStatus: form.activityStatus,
      connectionStatus: form.connectionStatus,
      activityLabel: activityLabels[form.activityStatus],
      connectionLabel: connectionLabels[form.connectionStatus],
      services: servicesArray,
    };

    try {
      await dispatch(createDevice(newDevicePayload)).unwrap();
      setIsAdding(false);
      setForm(initialForm);
      setFormError(undefined);
      setPage(1);
    } catch (apiError: any) {
      // Fallback: luu t?m v�o store d? user kh�ng m?t d? li?u khi mock API chua ch?y
      const nextId = Math.max(0, ...devices.map((d) => d.id || 0)) + 1;
      const fallbackDevice: DeviceItem = { id: nextId, ...newDevicePayload } as DeviceItem;
      dispatch(addDevice(fallbackDevice));
      setFormError(
        typeof apiError === 'string'
          ? `${apiError} (�� luu t?m trong b? nh?, c?n ch?y mock-api d? luu b?n v?ng)`
          : 'Kh�ng th? luu l�n mock API. �� luu t?m trong b? nh?.',
      );
      setIsAdding(false);
      setForm(initialForm);
      setPage(1);
    } finally {
      setSubmitting(false);
    }
  };

  const handleCancel = () => {
    setIsAdding(false);
    setForm(initialForm);
    setFormError(undefined);
  };

  return (
    <Layout style={{ minHeight: '100vh', backgroundColor: '#F6F6F6' }}>
      <Sider width={200} className="sider-custom">
        <div className="logo">
          <img src={`${process.env.PUBLIC_URL}/images/alta-logo.png`} alt="Alta Media" />
        </div>
        <Menu
          mode="vertical"
          defaultSelectedKeys={['2']}
          items={menuItems}
          className="sider-menu"
        />
        <Button
          className="logout-button"
          icon={<LogoutOutlined />}
          onClick={() => {
            localStorage.clear();
            window.location.reload();
          }}
        >
          �ang xu?t
        </Button>
      </Sider>

      <Layout>
        <Header className="header-custom">
          <Flex justify="space-between" align="center">
            <Breadcrumb separator={<RightOutlined style={{ fontSize: '12px', color: '#7E7D88' }} />}>
              <Breadcrumb.Item>Thi?t b?</Breadcrumb.Item>
              <Breadcrumb.Item className="breadcrumb-active">
                {isAdding ? 'Th�m thi?t b?' : 'Danh s�ch thi?t b?'}
              </Breadcrumb.Item>
            </Breadcrumb>
            <Space size="large" align="center">
              <BellOutlined style={{ fontSize: '20px', color: '#FF9138' }} />
              <Space>
                <Avatar src="https://i.pravatar.cc/32" />
                <div>
                  <Text style={{ fontSize: '12px', color: '#7E7D88' }}>Xin ch�o</Text>
                  <br />
                  <Text strong>Th�i Nhi</Text>
                </div>
              </Space>
            </Space>
          </Flex>
        </Header>

        <Content className="content-custom">
          <Title level={2} className="page-title">
            {isAdding ? 'Th�m thi?t b?' : 'Danh s�ch thi?t b?'}
          </Title>

          {isAdding ? (
            <div style={{ background: '#fff', padding: 24, borderRadius: 12, boxShadow: '0 2px 6px rgba(0,0,0,0.05)' }}>
              {formError && (
                <Alert
                  type="error"
                  message={formError}
                  showIcon
                  style={{ marginBottom: 16 }}
                />
              )}
              <Flex gap={32} wrap>
                <div style={{ flex: 1, minWidth: 320 }}>
                  <Text strong>M� thi?t b?</Text>
                  <Input
                    value={form.code}
                    onChange={(e) => handleFormChange('code', e.target.value)}
                    placeholder="V� d?: KIO_09"
                    style={{ marginBottom: 16 }}
                  />

                  <Text strong>T�n thi?t b?</Text>
                  <Input
                    value={form.name}
                    onChange={(e) => handleFormChange('name', e.target.value)}
                    placeholder="V� d?: Kiosk 09"
                    style={{ marginBottom: 16 }}
                  />

                  <Text strong>�?a ch? IP</Text>
                  <Input
                    value={form.ip}
                    onChange={(e) => handleFormChange('ip', e.target.value)}
                    placeholder="V� d?: 192.168.1.19"
                    style={{ marginBottom: 16 }}
                  />
                </div>

                <div style={{ flex: 1, minWidth: 320 }}>
                  <Text strong>Tr?ng th�i ho?t d?ng</Text>
                  <Select
                    value={form.activityStatus}
                    onChange={(val) => handleFormChange('activityStatus', val as ActivityStatus)}
                    style={{ width: '100%', marginBottom: 16 }}
                  >
                    <Option value="active">Ho?t d?ng</Option>
                    <Option value="inactive">Ngung ho?t d?ng</Option>
                  </Select>

                  <Text strong>Tr?ng th�i k?t n?i</Text>
                  <Select
                    value={form.connectionStatus}
                    onChange={(val) => handleFormChange('connectionStatus', val as ConnectionStatus)}
                    style={{ width: '100%', marginBottom: 16 }}
                  >
                    <Option value="connected">K?t n?i</Option>
                    <Option value="disconnected">M?t k?t n?i</Option>
                  </Select>

                  <Text strong>D?ch v? s? d?ng (ph�n t�ch b?ng d?u ph?y)</Text>
                  <Input.TextArea
                    value={form.services}
                    onChange={(e) => handleFormChange('services', e.target.value)}
                    placeholder="VD: Kh�m tim m?ch, Kh�m rang h�m m?t"
                    rows={3}
                    style={{ marginBottom: 16 }}
                  />
                </div>
              </Flex>

              <Flex justify="flex-end" gap={12}>
                <Button onClick={handleCancel}>H?y</Button>
                <Button type="primary" loading={submitting} onClick={handleSubmit} icon={<PlusOutlined />}>
                  Luu thi?t b?
                </Button>
              </Flex>
            </div>
          ) : (
            <>
              <Flex gap="large" align="flex-start">
                <div style={{ flex: 1 }}>
                  <Flex justify="space-between" align="flex-start" style={{ marginBottom: 16 }}>
                    <Space size="large">
                      <div>
                        <Text>Tr?ng th�i ho?t d?ng</Text>
                        <Select
                          value={activityFilter}
                          onChange={(value) => setActivityFilter(value as ActivityFilter)}
                          style={{ width: 300, display: 'block' }}
                        >
                          <Option value="all">T?t c?</Option>
                          <Option value="active">{activityLabels.active}</Option>
                          <Option value="inactive">{activityLabels.inactive}</Option>
                        </Select>
                      </div>

                      <div>
                        <Text>Tr?ng th�i k?t n?i</Text>
                        <Select
                          value={connectionFilter}
                          onChange={(value) => setConnectionFilter(value as ConnectionFilter)}
                          style={{ width: 300, display: 'block' }}
                        >
                          <Option value="all">T?t c?</Option>
                          <Option value="connected">{connectionLabels.connected}</Option>
                          <Option value="disconnected">{connectionLabels.disconnected}</Option>
                        </Select>
                      </div>
                    </Space>

                    <div>
                      <Text>T�m ki?m</Text>
                      <Input
                        placeholder="Nh?p t? kh�a"
                        suffix={<SearchOutlined style={{ color: '#FF9138' }} />}
                        style={{ width: 400, display: 'block' }}
                        value={keyword}
                        onChange={(e) => setKeyword(e.target.value)}
                        onPressEnter={() => setPage(1)}
                      />
                    </div>
                  </Flex>

                  {error && (
                    <Alert
                      type="error"
                      message="Kh�ng th? t?i danh s�ch thi?t b?"
                      description={error}
                      showIcon
                      style={{ marginBottom: 16 }}
                    />
                  )}

                  <Table
                    columns={columns}
                    dataSource={paginatedData}
                    rowKey="id"
                    loading={loading}
                    pagination={{
                      total: filteredData.length,
                      current: page,
                      pageSize,
                      showSizeChanger: false,
                      onChange: (nextPage) => setPage(nextPage),
                      itemRender: (current, type, originalElement) => {
                        if (type === 'prev') {
                          return <LeftOutlined />;
                        }
                        if (type === 'next') {
                          return <RightOutlined />;
                        }
                        return originalElement;
                      },
                    }}
                    className="device-table"
                  />
                </div>

                <Button className="add-device-button" onClick={handleAddDevice}>
                  <div className="add-icon-wrapper">
                    <PlusOutlined />
                  </div>
                  Th�m thi?t b?
                </Button>
              </Flex>
            </>
          )}
        </Content>
      </Layout>
    </Layout>
  );
};

export default Device;
